#!/usr/bin/env python
"""
Bootstrap: Degradation Safety Module (Designed Degradability)
REQUIRES: core/cascade_scaffold.py (for integration tests)
Run: python bootstrap_degradation_safety.py
"""
import base64, os, sys

if os.path.exists("core/universal_schema.py"): root = "."
elif os.path.exists("../core/universal_schema.py"): root = ".."
else: print("ERROR: Run from MABE root or one dir below."); sys.exit(1)

if not os.path.exists(os.path.join(root, "core/cascade_scaffold.py")):
    print("WARNING: core/cascade_scaffold.py not found. Integration tests will fail.")

_p = os.path.join(root, "core/degradation_safety.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

_p = os.path.join(root, "tests/test_degradation_safety.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

print("Done. Run: python -m pytest tests/test_degradation_safety.py -v")